// // This module decodes 4-bit inputs into 16-bit outputs. Only the least significant bit of the output is active when the input matches a decimal number from 0 to 15.
module decoder_4_to_16(  
    input [3:0] A,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        Y = 16'b0; // Deassert all outputs  
        Y[A] = 1'b1; // Assert the output corresponding to the input  
    end  
endmodule
